class Solution {
    public int getKth(int lo, int hi, int k) {
        int[] powers = new int[hi - lo + 1];
        for (int i = lo; i <= hi; i++) {
            int power = getPower(i);
            powers[i - lo] = power;
        }
        int[] sortedIndices = new int[hi - lo + 1];
        for (int i = 0; i < powers.length; i++) {
            sortedIndices[i] = i;
        }
        Arrays.sort(sortedIndices, (a, b) -> {
            if (powers[a] == powers[b]) {
                return a - b;
            } else {
                return powers[a] - powers[b];
            }
        });
        return lo + sortedIndices[k - 1];
    }

    private int getPower(int x) {
        int power = 0;
        while (x != 1) {
            if (x % 2 == 0) {
                x /= 2;
            } else {
                x = 3 * x + 1;
            }
            power++;
        }
        return power;
    }
}
